import java.util.Scanner;
import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");

        String userInput = scanner.nextLine();

        // Using ByteBuffer to handle the input securely
        ByteBuffer buffer = ByteBuffer.allocate(userInput.length());
        buffer.put(userInput.getBytes(StandardCharsets.UTF_8));

        System.out.println("Buffer contents: " + new String(buffer.array(), StandardCharsets.UTF_8));
    }
}

